#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <math.h>

#define N 20
#define K 6

void initializeRandomArray(int arr[], int n, int min, int max);
void swap(int *x, int *y);
void bubbleSort(int arr[], int n, int *comps);
float mean(int freq[], int n, int numValue);
void printFreqTable(int n, int comps[], int max);

int main() {
    time_t t;
    srand((unsigned)time(&t));
    int n = N;
    int TIMES[K] = {10, 20, 50, 100, 1000, 10000};
    int min = -1000, max = 1000;
    int arr[100];
    int comps = 0;
    for (int k = 0; k < K; k++) {
        int freq[N*(N-1)/2 + 1] = {0}; //because the worst case of Bubble Sort Algorithm is N * (N - 1) / 2 comparisons
        for (int i = 0; i < TIMES[k]; i++) {
            initializeRandomArray(arr, n, min, max);
            bubbleSort(arr, n, &comps);
            freq[comps]++;
        }
        printf("With k = %d:\nMean comparison: %f\n", TIMES[k], mean(freq, n*(n-1)/2, TIMES[k]));
        printFreqTable(n*(n-1)/2, freq, TIMES[k]);
        printf("\n");
    }
    return 0;
}

void initializeRandomArray(int arr[], int n, int min, int max) {
    for (int i = 0; i < n; i++) {
        arr[i] = min + rand() * (max - min + 1);
    }
}

void swap(int *x, int *y) {
    int temp = *x;
    *x = *y;
    *y = temp;
}

void bubbleSort(int arr[], int n, int *comps) {
    *comps = 0;
    for (int i = 0; i < n; i++) {
        for (int j = n - 1; j > i; j--) {
            (*comps)++;
            if (arr[j - 1] > arr[j]) swap(arr + j - 1, arr + j);
        }
    }
}

float mean(int freq[], int n, int numValue) {
    float sum = 0;
    for (int i = 0; i <= n; i++) {
        sum += i*freq[i];
    }
    return sum/numValue;
}

void printFreqTable(int n, int freq[], int max) {
    int len = log10(max) + 1;
    printf("Frequency Table:");
    printf("\nObsers: ");
    for (int i = 0; i <= n; i++) {
        printf("%*d ", len, i);
    }
    printf("\nComps : ");
    for (int i = 0; i <= n; i++) {
        printf("%*d ", len, freq[i]);
    }
    printf("\n");
}

